import{c as p,W as i,j as t,m as e}from"./chunks/framework.CoQR5MuA.js";const c=JSON.parse('{"title":"6-便民知识篇","description":"赞比亚国情资料 — 6-便民知识篇","frontmatter":{"title":"6-便民知识篇","description":"赞比亚国情资料 — 6-便民知识篇"},"headers":[],"relativePath":"mining/zambia/zh/06-daily-guide.md","filePath":"mining/zambia/zh/06-daily-guide.md","lastUpdated":1780402543000}'),r={name:"mining/zambia/zh/06-daily-guide.md"};function s(o,a,n,l,d,m){return i(),t("div",null,[...a[0]||(a[0]=[e('<h1 id="_6-便民知识篇" tabindex="-1">6-便民知识篇 <a class="header-anchor" href="#_6-便民知识篇" aria-label="Permalink to &quot;6-便民知识篇&quot;">​</a></h1><div class="reading-prose"><p><strong>便民知识篇</strong></p><p>**一、**<strong>解决商务纠纷的主要途径及适用的法律</strong></p><p>在赞比亚投资合作发生纠纷，可通过法院或仲裁机构解决，适用赞比亚法律。企业可以要求国际仲裁或异地仲裁。由于赞比亚独立时继承了英国法律制度，在司法实践中，法官可能援引英国普通法和衡平法。</p><ul><li>1、中资企业/人员在赞比亚如何寻求帮助</li></ul><p>赞比亚法律制度以英国法律制度为蓝本，并结合国情做出相应修改，属于普通法系。建议到赞比亚投资或承包工程的中资企业聘请专业律师或法律顾问，为公司开展业务、处理相关问题提供法律咨询服务。</p><p>赞比亚律师协会（Law Association of Zambia）的联系方式为： 电话：00260-211-254401；00260-211-252168</p><p>传真：00260-211-254428；00260-211-252173</p><p>电邮：secretariat@laz.org.zm</p><p>网址：www.laz.org.zm</p><ul><li>2、寻求当地政府帮助</li></ul><p>赞比亚发展署负责外商投资促进相关事宜，职能包括投资促进计划制定、发放投资许可证并提供投资所需其他服务、投资数据统计等。赞比亚移民局负责办理工作许可和零售业从业资格审核。发展署和移民局的联系方式详见附录。企业若有相关问题，可与以上机构联系。</p><p>若中资企业及旅赞侨民的人身和财产安全受到侵犯，可拨打991（移动电话拨打112）积极寻求当地警察帮助。</p><p>赞比亚警察署网站（www.zambiapolice.gov.zm）载有各省及地区分部的联系方式，可登陆查阅。</p><ul><li>3、取得中国驻赞比亚大使馆保护</li></ul><p>中国驻赞比亚大使馆对中资企业和华商华人提供领事保护，具体领事保护政策请参见《中国领事保护和协助指南》（zm.chineseembassy.org/chn/lsfw/lsxw/t944997.htm）。</p><p>按照中国国内有关规定，中资企业在赞比亚开展投资合作前应首先报请国内主管部门审批，并征求中国驻赞比亚大使馆经商处意见。进入赞比亚市场后应向使馆经商处报到备案，并与经商处保持定期工作联系，遇到重大问题要及时向经商处汇报，听取使馆和经商处意见，在中国驻赞使馆和经商处以及国内主管部门共同领导下，妥善处理好所发生的重大问题和事件。</p><p>【当地应急电话】报警：991；医疗急救：992；首都卢萨卡地区急救：995；消防火警：993；紧急情况：999。</p><p>【赞比亚华人华侨紧急医疗救助队】 紧急救助电话：00260-962100111。</p><p><strong>二、医疗保险</strong></p><p>首都卢萨卡有全国最大的公立医院：赞比亚大学教学医院（UTH）紧急救助电话：00260-211-251451。援赞医疗队所在的利维·姆瓦纳瓦萨医院和援赞军医组所在的三军总医院也能为患重大疾病的中国公民提供紧急救助。</p><p>在铜带省基特韦市，赞中经贸合作区所属的中赞友谊医院拥有中国医生和一定的医疗条件。当地保险业有一定规模。中国公民和企业可自行选择保险经纪公司购买人身或医疗保险。</p><p><strong>三、便民掌握信息</strong></p></div>',2)])])}const g=p(r,[["render",s]]);export{c as __pageData,g as default};
